52		wire [7:0] RA = {RADR_7, RADR_6, RADR_5, RADR_4, RADR_3, RADR_2, RADR_1, RADR_0};
53		wire [7:0] WA = {WADR_7, WADR_6, WADR_5, WADR_4, WADR_3, WADR_2, WADR_1, WADR_0};
54		wire [7:0] WD = {WD_7, WD_6, WD_5, WD_4, WD_3, WD_2, WD_1, WD_0};
55	
56		wire [7:0] RD;
57		assign {RD_7, RD_6, RD_5, RD_4, RD_3, RD_2, RD_1, RD_0} = RD;
58		wire [1:0] SVOP = {SVOP_1, SVOP_0};
59	    wire [7:0] SLEEP_EN = {SLEEP_EN_7, SLEEP_EN_6, SLEEP_EN_5, SLEEP_EN_4, SLEEP_EN_3, SLEEP_EN_2, SLEEP_EN_1, SLEEP_EN_0};
60	    
61	
62	`ifndef EMULATION
63	`ifndef SYNTHESIS
64	
65	    //State point clobering signals:
66	    wire check_x = (SVOP_0 ^ SVOP_1);
67	    wire clobber_x;
68	    assign clobber_x = ((check_x === 1'bx) || (check_x === 1'bz)) ? 1'b1 : 1'b0;
69	    wire clobber_array = ((|SLEEP_EN) & ~RET_EN) | clobber_x;
70	    wire clobber_flops = (|SLEEP_EN) | clobber_x;
71	    integer i;
72	    always  @(clobber_array) begin
73	      if (clobber_array) begin
74	    		for (i=0; i<256; i=i+1) begin
75	    		    ITOP.io.array[i] <= 8'bx;
76	    		end
77	      end
78	    end
79	
80	//VCS coverage off     
81	    always  @(clobber_flops) begin
82	        if (clobber_flops) begin
83	        ITOP.we_lat <= 1'bx;
84	        ITOP.wa_lat <= 8'bx;
85	        ITOP.wd_lat <= 8'bx;
86	        
87	        ITOP.re_lat <= 1'bx;
88	        ITOP.ra_lat <= 8'bx;
89	        ITOP.io.r0_dout_tmp <= 8'b0;
90	        end
91	    end
92	//VCS coverage on    
93	
94	//VCS coverage off
95	`ifdef NV_RAM_ASSERT
96	    //first reset signal for nv_assert_module:
97	    reg sim_reset;                                                     
98	    initial begin: init_sim_reset
99	        sim_reset = 0;  
100	        #6 sim_reset = 1;
101	    end
102	
103	    reg rst_clk;                                                     
104	    initial begin: init_rst_clk
105	        rst_clk = 0; 
106	        #2 rst_clk = 1; 
107	        #4 rst_clk = 0;  
108	    end
109	
110	    //internal weclk|reclk gating signal:
111	    wire weclk_gating = ITOP.we_lat & ~IDDQ;
112	    wire reclk_gating = ITOP.re_lat & ~IDDQ;
113	
114	  //Assertion checks for power sequence of G-option RAMDP:
115	
116	    //weclk_gating after 2 clk
117	    reg weclk_gating_1p, weclk_gating_2p;
118	    always @(posedge CLK_W) begin
119	        weclk_gating_1p <= weclk_gating;
120	        weclk_gating_2p <= weclk_gating_1p;
121	    end
122	
123	    //reclk_gating after 2 clk
124	    reg reclk_gating_1p, reclk_gating_2p;
125	    always @(posedge CLK_R) begin
126	        reclk_gating_1p <= reclk_gating;
127	        reclk_gating_2p <= reclk_gating_1p;
128	    end
129	    
130	    //RET_EN off after 2 CLK_W
131	    reg ret_en_w_1p, ret_en_w_2p;
132	    always @(posedge CLK_W or posedge RET_EN) begin
133	        if(RET_EN) 
134	            begin
135	                ret_en_w_1p <= 1'b1;
136	                ret_en_w_2p <= 1'b1;
137	            end
138	        else
139	            begin
140	                ret_en_w_1p <= RET_EN;
141	                ret_en_w_2p <= ret_en_w_1p;
142	            end
143	    end
144	
145	    //RET_EN off after 2 CLK_R
146	    reg ret_en_r_1p, ret_en_r_2p;
147	    always @(posedge CLK_R or posedge RET_EN) begin
148	        if(RET_EN) 
149	            begin
150	                ret_en_r_1p <= 1'b1;
151	                ret_en_r_2p <= 1'b1;
152	            end
153	        else
154	            begin
155	                ret_en_r_1p <= RET_EN;
156	                ret_en_r_2p <= ret_en_r_1p;
157	            end
158	    end
159	
160	    wire sleep_en_or = (|SLEEP_EN) ;
161	    //SLEEP_EN off after 2 CLK_W
162	    reg sleep_en_off_w_1p, sleep_en_off_w_2p;
163	    always @(posedge CLK_W or posedge sleep_en_or) begin
164	        if(sleep_en_or)
165	            begin
166	                sleep_en_off_w_1p <= 1'b1;
167	                sleep_en_off_w_2p <= 1'b1;
168	            end
169	        else
170	            begin
171	                sleep_en_off_w_1p <= sleep_en_or;
172	                sleep_en_off_w_2p <= sleep_en_off_w_1p;
173	            end            
174	    end
175	
176	    //SLEEP_EN off after 2 CLK_R
177	    reg sleep_en_off_r_1p, sleep_en_off_r_2p;
178	    always @(posedge CLK_R or posedge sleep_en_or) begin
179	        if(sleep_en_or)
180	            begin
181	                sleep_en_off_r_1p <= 1'b1;
182	                sleep_en_off_r_2p <= 1'b1;
183	            end
184	        else
185	            begin
186	                sleep_en_off_r_1p <= |sleep_en_or;
187	                sleep_en_off_r_2p <= sleep_en_off_r_1p;
188	            end            
189	    end    
190	
191	
192	  //#1 From function mode to retention mode:
193	    
194	    //Power-S1.1:illegal assert RET_EN after asserting SLEEP_EN 
195	    wire disable_power_assertion_S1P1 = $test$plusargs("disable_power_assertions_globally") | $test$plusargs("disable_power_assertion_assert_RET_EN_after_SLEEP_EN_on_when_function2retention");
196	    nv_assert_never #(0,0, "Power-S1.1:illegal assert RET_EN after asserting SLEEP_EN") inst_S1P1 (RET_EN ^ rst_clk, ~disable_power_assertion_S1P1 & sim_reset, (|SLEEP_EN));
197	
198	    //Power-S1.2:illegal assert RET_EN without 2 nop-CLK
199	    wire disable_power_assertion_S1P2 = $test$plusargs("disable_power_assertions_globally") | $test$plusargs("disable_power_assertion_assert_RET_EN_without_2_nop_CLK");
200	    nv_assert_never #(0,0, "Power-S1.2:illegal assert RET_EN without 2 nop-CLK") inst_S1P2 (RET_EN ^ rst_clk, ~disable_power_assertion_S1P2 & sim_reset, weclk_gating | weclk_gating_1p | weclk_gating_2p | reclk_gating | reclk_gating_1p | reclk_gating_2p);
201	
202	  //#2 From retention mode to function mode:
203	
204	    //Power-S2.1:illegal write without 2 nop-CLK after de-asserting RET_EN
205	    wire disable_power_assertion_S2P1 = $test$plusargs("disable_power_assertions_globally") | $test$plusargs("disable_power_assertion_write_without_2_nop_CLK_after_retention2function");
206	    nv_assert_never #(0,0, "Power-S2.1:illegal write without 2 nop-CLK after de-asserting RET_EN") inst_S2P1 (CLK_W ^ rst_clk, ~disable_power_assertion_S2P1 & sim_reset, ~RET_EN & ret_en_w_2p & weclk_gating);
207	
208	    //Power-S2.2:illegal read without 2 nop-CLK after de-asserting RET_EN
209	    wire disable_power_assertion_S2P2 = $test$plusargs("disable_power_assertions_globally") | $test$plusargs("disable_power_assertion_read_without_2_nop_CLK_after_retention2function");
210	    nv_assert_never #(0,0, "Power-S2.2:illegal read without 2 nop-CLK after de-asserting RET_EN") inst_S2P2 (CLK_R ^ rst_clk, ~disable_power_assertion_S2P2 & sim_reset, ~RET_EN & ret_en_r_2p & reclk_gating);
211	
212	  //#3 From function mode to sleep mode:
213	
214	    //Power-S3.2:illegal assert SLEEP_EN without 2 nop-CLK
215	    wire disable_power_assertion_S3P2 = $test$plusargs("disable_power_assertions_globally") | $test$plusargs("disable_power_assertion_assert_SLEEP_EN_without_2_nop_CLK");
216	    nv_assert_never #(0,0, "Power-S3.2:illegal assert SLEEP_EN without 2 nop-CLK") inst_S3P2 ((|SLEEP_EN) ^ rst_clk, ~disable_power_assertion_S3P2 & sim_reset, weclk_gating | weclk_gating_1p | weclk_gating_2p | reclk_gating | reclk_gating_1p | reclk_gating_2p);
217	
218	  //#4 From sleep mode to function mode:
219	
220	    //Power-S4.1:illegal write without 2 nop-CLK after switching from sleep mode to function mode
221	    wire disable_power_assertion_S4P1 = $test$plusargs("disable_power_assertions_globally") | $test$plusargs("disable_power_assertion_write_without_2_nop_CLK_after_sleep2function");
222	    nv_assert_never #(0,0, "Power-S4.1:illegal write without 2 nop-CLK after switching from sleep mode to function mode") inst_S4P1 (CLK_W ^ rst_clk, ~disable_power_assertion_S4P1 & sim_reset, ~(|SLEEP_EN) & sleep_en_off_w_2p & weclk_gating);
223	   
224	    //Power-S4.2:illegal read without 2 nop-CLK after switching from sleep mode to function mode
225	    wire disable_power_assertion_S4P2 = $test$plusargs("disable_power_assertions_globally") | $test$plusargs("disable_power_assertion_read_without_2_nop_after_sleep2function");
226	    nv_assert_never #(0,0, "Power-S4.2:illegal read without 2 nop-CLK after switching from sleep mode to function mode") inst_S4P2 (CLK_R ^ rst_clk, ~disable_power_assertion_S4P2 & sim_reset, ~(|SLEEP_EN) & sleep_en_off_r_2p & reclk_gating);
227	`endif //NV_RAM_ASSERT
