776	`ifndef RAM_INTERFACE
777	`ifndef EMULATION
778	module RAM_BANK_RAMDP_256X8_GL_M2_E2 (RE, WE, RA, WA, CLK_R, CLK_W, IDDQ, SVOP, WD, RD, SLEEP_EN, RET_EN, clobber_flops, clobber_array, clobber_x
779	);
780	
781	
782	input RET_EN;
783	input RE, WE, CLK_R, CLK_W, IDDQ;
784	input [7:0] RA, WA;
785	input [7:0] WD;
786	input [1:0] SVOP;
787	input [7:0] SLEEP_EN;
788	input clobber_flops, clobber_array, clobber_x;
789	output [7:0] RD;
790	
791	//State point clobering signals:
792	
793	    wire output_valid = ~(clobber_x | (|SLEEP_EN));
794	    wire clamp_o = SLEEP_EN[7] | RET_EN;
795	
796		//common part for write
797	    wire clk_w_iddq = CLK_W & ~IDDQ & ~clamp_o;
798		reg we_lat;
799		always @(*) begin
800			if (!clk_w_iddq & !clobber_flops) begin
801				we_lat  <=  WE; // spyglass disable W18, IntClock
802			end
803		end
804	
805	    // weclk with posedge 1 dly | negedge 2 dly	
806	    wire weclk, weclk_d0, weclk_d1, weclk_d2;
807	    assign weclk_d0 = clk_w_iddq & we_lat & ~clobber_flops & ~clobber_array;
808	    assign #1 weclk_d1 = weclk_d0;
809	    assign #1 weclk_d2 = weclk_d1;
810	    assign weclk = weclk_d1 | weclk_d2; // spyglass disable GatedClock
811	
812	    // wadclk with posedge 0 dly | negedge 3 dly	
813	    wire wadclk, wadclk_d0, wadclk_d1, wadclk_d2, wadclk_d3;
814	    assign wadclk_d0 = clk_w_iddq & we_lat;
815	    assign #1 wadclk_d1 = wadclk_d0;
816	    assign #1 wadclk_d2 = wadclk_d1;
817	    assign #1 wadclk_d3 = wadclk_d2;
818	    assign wadclk = wadclk_d0 | wadclk_d1 | wadclk_d2 | wadclk_d3;  
819	
820	    // wdclk with posedge 0 dly | negedge 3 dly
821	    wire wdclk, wdclk_d0, wdclk_d1, wdclk_d2, wdclk_d3;
822	    assign wdclk_d0 = clk_w_iddq & we_lat;
823	    assign #1 wdclk_d1 = wdclk_d0;
824	    assign #1 wdclk_d2 = wdclk_d1;
825	    assign #1 wdclk_d3 = wdclk_d2;
826	    assign wdclk = wdclk_d0 | wdclk_d1 | wdclk_d2 | wdclk_d3;  
827	
828	    reg [7:0] wa_lat;
829		always @(*) begin
830			if (!wadclk & !clobber_flops) begin
831				wa_lat  <=  WA; // spyglass disable W18, IntClock
832			end
833		end
834	
835		reg [7:0] wd_lat;
836		always @(*) begin
837			if (!wdclk & !clobber_flops) begin
838				wd_lat  <= WD; // spyglass disable W18, IntClock
839			end
840		end
841	
842		//common part for read
843		reg re_lat;
844		always @(*) begin
845			if (!CLK_R & !clobber_flops) begin
846				re_lat <=  RE; // spyglass disable W18, IntClock
847			end
848		end
849	
850	    // reclk with posedge 1 dly | negedge 0 dly
851	    wire reclk, reclk_d0, reclk_d1;
852	    assign reclk_d0 = CLK_R & ~IDDQ & re_lat & ~clamp_o;
853	    assign #1 reclk_d1 = reclk_d0;
854	    assign reclk = reclk_d0 & reclk_d1; // spyglass disable GatedClock
855	
856	    // radclk with posedge 0 dly | negedge 1 dly
857	    wire radclk, radclk_d0, radclk_d1;
858	    assign radclk_d0 = CLK_R & ~IDDQ & re_lat & ~clamp_o;
859	    assign #1 radclk_d1 = radclk_d0;
860	    assign radclk = radclk_d0 | radclk_d1;  
861	
862		reg [7:0] ra_lat;
863		always @(*) begin
864			if (!radclk & !clobber_flops) begin
865				ra_lat <=  RA; // spyglass disable W18, IntClock
866			end
867		end
868		
869		wire [7:0] dout;
870		assign RD = clamp_o ? 8'b0 : (output_valid ? dout : 8'bx); //spyglass disable STARC-2.10.1.6
871	
872	
873		//for E-option RAM
874	
875	
876		vram_RAMDP_256X8_GL_M2_E2 # (256, 8, 8) io (
877			.w0_addr(wa_lat),
878			.w0_clk(weclk),
879			.w0_bwe({8{1'b1}}),
880			.w0_din(wd_lat),
881			.r0_addr(ra_lat),
882			.r0_clk(reclk),
883			.r0_dout(dout),
884	        .clamp_o(clamp_o)
885		);
886	
887	endmodule
888	`endif //ndef EMULATION
889	`endif //ndef RAM_INTERFACE
