894	
895	
896	
897	
898	/////////////////////////////////////////////////////////////////////////////////////////////////////////////////////////////////
899	///////////////////////////////  ram primitive : defines 2D behavioral memory array of the RAMDP ////////////////////////////////
900	/////////////////////////////////////////////////////////////////////////////////////////////////////////////////////////////////
901	
902	`ifndef RAM_INTERFACE
903	`ifndef EMULATION
904	module vram_RAMDP_256X8_GL_M2_E2 (
905		w0_addr,
906		w0_clk,
907		w0_bwe,
908		w0_din,
909		r0_addr,
910		r0_clk,
911		r0_dout,
912	    clamp_o
913	);
914	
915	parameter words = 256;
916	parameter bits = 8;
917	parameter addrs = 8;
918	
919	
920	input [addrs-1:0] w0_addr;
921	input w0_clk;
922	input [bits-1:0] w0_din;
923	input [bits-1:0] w0_bwe;
924	input [addrs-1:0] r0_addr;
925	input r0_clk;
926	input clamp_o;
927	output [bits-1:0] r0_dout;
928	
929	integer a;
930	
931	`ifndef SYNTHESIS
932	`ifdef FAULT_INJECTION
933		// regs for inducing faults
934		reg [bits-1:0] fault_no_write; // block writes to this column
935		reg [bits-1:0] fault_stuck_0;  // column always reads as 0
936		reg [bits-1:0] fault_stuck_1;  // column always reads as 1
937		reg [bits-1:0] bit_fault_stuck_0[0:words-1];  // column always reads as 0
938		reg [bits-1:0] bit_fault_stuck_1[0:words-1];  // column always reads as 1
939		
940		initial begin : init_bit_fault_stuck
941		  integer i;
942		  integer j;
943		  fault_no_write = {bits{1'b0}};
944		  fault_stuck_0  = {bits{1'b0}};
945		  fault_stuck_1  = {bits{1'b0}};
946		  for (i=0; i<=words; i=i+1) begin
947		      bit_fault_stuck_0[i] = {bits{1'b0}};
948		      bit_fault_stuck_1[i] = {bits{1'b0}};
949		  end
950		end
951	`endif //def FAULT_INJECTION
952	
953	`ifdef MONITOR
954	//VCS coverage off
955	// monitor variables
956	reg monitor_on;
957	reg dump_monitor_result;
958	// this monitors coverage including redundancy cols
959	// 1'bx = not accessed
960	// 1'b0 = accessed as a 0
961	// 1'b1 = accessed as a 1
962	// 1'bz = accessed as both 0 and 1
963	reg [bits-1:0] bit_written[0:words-1];
964	reg [bits-1:0] bit_read[0:words-1];
965	
966	initial begin : init_monitor
967	  monitor_on = 1'b0; 
968	  dump_monitor_result = 1'b0;
969	  for(a=0;a<words;a=a+1) begin
970	      bit_written[a] = {bits{1'bx}};
971	      bit_read[a] = {bits{1'bx}};
972	  end
973	end
974	
975	always @(dump_monitor_result) begin : dump_monitor
976	    integer r;
977		integer c;
978	    integer b;
979		reg [16-1:0] tmp_row;
980	    	if (dump_monitor_result == 1'b1) begin
981			    $display("Exercised coverage summary:");
982			    $display("\t%m bits not written as 0:");
983			    for (r=0; r<128; r=r+1) begin
984			        for (b=0; b<bits; b=b+1) begin
985	                        tmp_row[b*2+0] = bit_written[r*2+0][b];
986	                        tmp_row[b*2+1] = bit_written[r*2+1][b];
987	                    end
988			    	for (c=0; c<16; c=c+1) begin
989			    		if (tmp_row[c] !== 1'b0 && tmp_row[c] !== 1'bz) $display("\t\t[row,col] [%d,%d]", r, c);
990			    	end
991			    end
992	            $display("\t%m bits not written as 1:");
993			    for (r=0; r<128; r=r+1) begin
994			        for (b=0; b<bits; b=b+1) begin
995	                        tmp_row[b*2+0] = bit_written[r*2+0][b];
996	                        tmp_row[b*2+1] = bit_written[r*2+1][b];
997	                    end
998			    	for (c=0; c<16; c=c+1) begin
999			    		if (tmp_row[c] !== 1'b1 && tmp_row[c] !== 1'bz) $display("\t\t[row,col] [%d,%d]", r, c);
1000			    	end
1001			    end
1002			    $display("\t%m bits not read as 0:");
1003			    for (r=0; r<128; r=r+1) begin
1004			        for (b=0; b<bits; b=b+1) begin
1005	                        tmp_row[b*2+0] = bit_read[r*2+0][b];
1006	                        tmp_row[b*2+1] = bit_read[r*2+1][b];
1007	                    end
1008			    	for (c=0; c<16; c=c+1) begin
1009			    		if (tmp_row[c] !== 1'b0 && tmp_row[c] !== 1'bz) $display("\t\t[row,col] [%d,%d]", r, c);
1010			    	end
1011			    end
1012			    $display("\t%m bits not read as 1:");
1013			    for (r=0; r<128; r=r+1) begin
1014			        for (b=0; b<bits; b=b+1) begin
1015	                        tmp_row[b*2+0] = bit_read[r*2+0][b];
1016	                        tmp_row[b*2+1] = bit_read[r*2+1][b];
1017	                    end
1018			    	for (c=0; c<16; c=c+1) begin
1019			    		if (tmp_row[c] !== 1'b1 && tmp_row[c] !== 1'bz) $display("\t\t[row,col] [%d,%d]", r, c);
1020			    	end
1021			    end
1022	        end
1023		dump_monitor_result = 1'b0;
1024	end
1025	//VCS coverage on
1026	`endif //MONITOR
1027	`endif //ndef SYNTHESIS
1028		
1029		//memory array
1030		reg [bits-1:0] array[0:words-1];  
1031	
1032	// Bit write enable
1033	`ifndef SYNTHESIS 
1034	    `ifdef FAULT_INJECTION
1035	        wire [bits-1:0] bwe_with_fault = w0_bwe & ~fault_no_write;
1036	        wire [bits-1:0] re_with_fault = ~(bit_fault_stuck_1[r0_addr] | bit_fault_stuck_0[r0_addr]);
1037	    `else
1038	        wire [bits-1:0] bwe_with_fault = w0_bwe;
1039	        wire [bits-1:0] re_with_fault = {bits{1'b1}};
1040	    `endif //def FAULT_INJECTION
1041	`else
1042	    wire [bits-1:0] bwe_with_fault = w0_bwe;
1043	`endif //SYNTHESIS
1044	
1045		//write function
1046	    wire [bits-1:0] bitclk = {bits{w0_clk}} & bwe_with_fault;
1047	    genvar idx;
1048	    generate
1049	        for (idx=0; idx<bits; idx=idx+1)
1050	        begin : write
1051	            always @(bitclk[idx] or w0_clk or w0_addr or w0_din[idx])
1052	            begin
1053	                if (bitclk[idx] && w0_clk)
1054	                begin
1055	                    array[w0_addr][idx] <= w0_din[idx]; // spyglass disable SYNTH_5130, W18
1056	                    `ifndef SYNTHESIS
1057	                    `ifdef MONITOR
1058	//VCS coverage off
1059	                    if (monitor_on) begin 
1060		    				case (bit_written[w0_addr][idx])
1061		    				    1'bx: bit_written[w0_addr][idx] = w0_din[idx];
1062		    				    1'b0: bit_written[w0_addr][idx] = w0_din[idx] == 1 ? 1'bz : 1'b0;
1063		    				    1'b1: bit_written[w0_addr][idx] = w0_din[idx] == 0 ? 1'bz : 1'b1;
1064		    				    1'bz: bit_written[w0_addr][idx] = 1'bz;
1065		    				endcase
1066	                    end   
1067	//VCS coverage on
1068	                    `endif //MONITOR	    
1069	                    `endif //SYNTHESIS	
1070	                end
1071	            end
1072	        end
1073	    endgenerate
1074	
1075		//read function
1076		wire [bits-1:0] r0_arr;
1077	`ifndef SYNTHESIS
1078	    `ifdef FAULT_INJECTION
1079		    assign r0_arr = (array[r0_addr] | bit_fault_stuck_1[r0_addr]) & ~bit_fault_stuck_0[r0_addr]; //read fault injection
1080	    `else
1081		    assign r0_arr = array[r0_addr]; 
1082	    `endif //def FAULT_INJECTION
1083	`else
1084	    assign r0_arr = array[r0_addr]; // spyglass disable SYNTH_5130
1085	`endif //def SYNTHESIS
1086	
1087	
1088	    wire r0_clk_d0p1, r0_clk_read, r0_clk_reset_collision;
1089	    assign #0.1 r0_clk_d0p1 = r0_clk;
1090	    assign r0_clk_read = r0_clk_d0p1 & r0_clk; // spyglass disable GatedClock
1091	    assign r0_clk_reset_collision = r0_clk | r0_clk_d0p1; // spyglass disable W402b
1092	
1093	`ifndef SYNTHESIS
1094	`ifdef MONITOR
1095	//VCS coverage off 
1096	    always @(r0_clk_read) begin
1097	        if (monitor_on) begin
1098	            for (a=0; a<bits; a=a+1) begin
1099		            if (re_with_fault[a] && r0_clk_read) begin
1100		                case (bit_read[r0_addr][a])
1101				            1'bx: bit_read[r0_addr][a] = array[r0_addr][a];
1102					        1'b0: bit_read[r0_addr][a] = array[r0_addr][a] == 1 ? 1'bz : 1'b0;
1103					        1'b1: bit_read[r0_addr][a] = array[r0_addr][a] == 0 ? 1'bz : 1'b1;
1104					        1'bz: bit_read[r0_addr][a] = 1'bz;
1105			            endcase
1106		            end
1107		        end
1108	        end
1109	    end
1110	//VCS coverage on
1111	`endif //MONITOR
1112	`endif //SYNTHESIS
1113	
1114		reg [bits-1:0] collision_ff;
1115	    wire [bits-1:0] collision_ff_clk =  {bits{w0_clk}} & {bits{r0_clk_read}} & {bits{r0_addr==w0_addr}} & bwe_with_fault; //spyglass disable GatedClock
1116	    genvar bw;
1117	    generate
1118	        for (bw=0; bw<bits; bw=bw+1) 
1119	        begin : collision
1120		        always @(posedge collision_ff_clk[bw] or negedge r0_clk_reset_collision) begin
1121	                if (!r0_clk_reset_collision) 
1122	                    begin
1123	                        collision_ff[bw] <= 1'b0;
1124	                    end
1125	                else
1126	                    begin
1127	                        collision_ff[bw] <= 1'b1;
1128	                    end
1129	            end
1130	        end
1131	    endgenerate
1132	
1133		reg [bits-1:0] r0_dout_tmp;
1134		always @(*)
1135		begin
1136		    if (r0_clk_read) begin
1137	            for (a=0; a<bits; a=a+1) begin
1138	                r0_dout_tmp[a] <= ( collision_ff[a] | (r0_addr==w0_addr & w0_clk & bwe_with_fault[a]) ) ? 1'bx : r0_arr[a] & ~clamp_o; //spyglass disable STARC-2.10.1.6, W18
1139	            end
1140	        end
1141	    end
1142	    wire [bits-1:0] r0_dout = r0_dout_tmp & {bits{~clamp_o}};
1143	
1144	`ifndef SYNTHESIS
1145	//VCS coverage off
1146	task mem_wr_raw;
1147	  input [addrs-1:0] addr;
1148	  input [bits-1:0] data;
1149	  begin
1150	    array[addr] = data;
1151	  end
1152	endtask
1153	
1154	function [bits-1:0] mem_read_raw;
1155	input [addrs-1:0] addr;
1156		mem_read_raw = array[addr];
1157	endfunction
1158	
1159	`ifdef FAULT_INJECTION
1160	// induce faults on columns
1161	task mem_fault_no_write;
1162	  input [bits-1:0] fault_mask;
1163	   begin
1164	    fault_no_write = fault_mask;
1165	  end
1166	endtask
1167	
1168	task mem_fault_stuck_0;
1169	  input [bits-1:0] fault_mask;
1170	  integer i;
1171	   begin
1172	    for ( i=0; i<words; i=i+1 ) begin
1173	      bit_fault_stuck_0[i] = fault_mask;
1174	    end
1175	  end
1176	endtask
1177	
1178	task mem_fault_stuck_1;
1179	  input [bits-1:0] fault_mask;
1180	  integer i;
1181	   begin
1182	    for ( i=0; i<words; i=i+1 ) begin
1183	      bit_fault_stuck_1[i] = fault_mask;
1184	    end
1185	  end
1186	endtask
1187	
1188	task set_bit_fault_stuck_0;
1189	  input r;
1190	  input c;
1191	  integer r;
1192	  integer c;
1193	  bit_fault_stuck_0[r][c] = 1;
1194	endtask
1195	
1196	task set_bit_fault_stuck_1;
1197	  input r;
1198	  input c;
1199	  integer r;
1200	  integer c;
1201	  bit_fault_stuck_1[r][c] = 1;
1202	endtask
1203	
1204	task clear_bit_fault_stuck_0;
1205	  input r;
1206	  input c;
1207	  integer r;
1208	  integer c;
1209	  bit_fault_stuck_0[r][c] = 0;
1210	endtask
1211	
1212	task clear_bit_fault_stuck_1;
1213	  input r;
1214	  input c;
1215	  integer r;
1216	  integer c;
1217	  bit_fault_stuck_1[r][c] = 0;
1218	endtask
1219	//VCS coverage on
1220	`endif //def FAULT_INJECTION
1221	`endif //ndef SYNTHESIS
1222	
1223	endmodule
1224	`endif //ndef EMULATION
1225	`endif //ndef RAM_INTERFACE
