502	`ifndef RAM_INTERFACE
503	`ifndef EMULATION
504	module RAM_BANK_RAMDP_16X256_GL_M1_E2 (RE, WE, RA, WA, CLK_R, CLK_W, IDDQ, SVOP, WD, RD, SLEEP_EN, RET_EN, clobber_flops, clobber_array, clobber_x
505	);
506	
507	
508	input RET_EN;
509	input RE, WE, CLK_R, CLK_W, IDDQ;
510	input [3:0] RA, WA;
511	input [255:0] WD;
512	input [1:0] SVOP;
513	input [7:0] SLEEP_EN;
514	input clobber_flops, clobber_array, clobber_x;
515	output [255:0] RD;
516	
517	//State point clobering signals:
518	
519	    wire output_valid = ~(clobber_x | (|SLEEP_EN));
520	    wire clamp_o = SLEEP_EN[7] | RET_EN;
521	
522		//common part for write
523	    wire clk_w_iddq = CLK_W & ~IDDQ & ~clamp_o;
524		reg we_lat;
525		always @(*) begin
526			if (!clk_w_iddq & !clobber_flops) begin
527				we_lat  <=  WE; // spyglass disable W18, IntClock
528			end
529		end
530	
531	    // weclk with posedge 1 dly | negedge 2 dly	
532	    wire weclk, weclk_d0, weclk_d1, weclk_d2;
533	    assign weclk_d0 = clk_w_iddq & we_lat & ~clobber_flops & ~clobber_array;
534	    assign #1 weclk_d1 = weclk_d0;
535	    assign #1 weclk_d2 = weclk_d1;
536	    assign weclk = weclk_d1 | weclk_d2; // spyglass disable GatedClock
537	
538	    // wadclk with posedge 0 dly | negedge 3 dly	
539	    wire wadclk, wadclk_d0, wadclk_d1, wadclk_d2, wadclk_d3;
540	    assign wadclk_d0 = clk_w_iddq & we_lat;
541	    assign #1 wadclk_d1 = wadclk_d0;
542	    assign #1 wadclk_d2 = wadclk_d1;
543	    assign #1 wadclk_d3 = wadclk_d2;
544	    assign wadclk = wadclk_d0 | wadclk_d1 | wadclk_d2 | wadclk_d3;  
545	
546	    // wdclk with posedge 0 dly | negedge 3 dly
547	    wire wdclk, wdclk_d0, wdclk_d1, wdclk_d2, wdclk_d3;
548	    assign wdclk_d0 = clk_w_iddq & we_lat;
549	    assign #1 wdclk_d1 = wdclk_d0;
550	    assign #1 wdclk_d2 = wdclk_d1;
551	    assign #1 wdclk_d3 = wdclk_d2;
552	    assign wdclk = wdclk_d0 | wdclk_d1 | wdclk_d2 | wdclk_d3;  
553	
554	    reg [3:0] wa_lat;
555		always @(*) begin
556			if (!wadclk & !clobber_flops) begin
557				wa_lat  <=  WA; // spyglass disable W18, IntClock
558			end
559		end
560	
561		reg [255:0] wd_lat;
562		always @(*) begin
563			if (!wdclk & !clobber_flops) begin
564				wd_lat  <= WD; // spyglass disable W18, IntClock
565			end
566		end
567	
568		//common part for read
569		reg re_lat;
570		always @(*) begin
571			if (!CLK_R & !clobber_flops) begin
572				re_lat <=  RE; // spyglass disable W18, IntClock
573			end
574		end
575	
576	    // reclk with posedge 1 dly | negedge 0 dly
577	    wire reclk, reclk_d0, reclk_d1;
578	    assign reclk_d0 = CLK_R & ~IDDQ & re_lat & ~clamp_o;
579	    assign #1 reclk_d1 = reclk_d0;
580	    assign reclk = reclk_d0 & reclk_d1; // spyglass disable GatedClock
581	
582	    // radclk with posedge 0 dly | negedge 1 dly
583	    wire radclk, radclk_d0, radclk_d1;
584	    assign radclk_d0 = CLK_R & ~IDDQ & re_lat & ~clamp_o;
585	    assign #1 radclk_d1 = radclk_d0;
586	    assign radclk = radclk_d0 | radclk_d1;  
587	
588		reg [3:0] ra_lat;
589		always @(*) begin
590			if (!radclk & !clobber_flops) begin
591				ra_lat <=  RA; // spyglass disable W18, IntClock
592			end
593		end
594		
595		wire [255:0] dout;
596		assign RD = clamp_o ? 256'b0 : (output_valid ? dout : 256'bx); //spyglass disable STARC-2.10.1.6
597	
598	
599		//for E-option RAM
600	
601	
602		vram_RAMDP_16X256_GL_M1_E2 # (16, 256, 4) io (
603			.w0_addr(wa_lat),
604			.w0_clk(weclk),
605			.w0_bwe({256{1'b1}}),
606			.w0_din(wd_lat),
607			.r0_addr(ra_lat),
608			.r0_clk(reclk),
609			.r0_dout(dout),
610	        .clamp_o(clamp_o)
611		);
612	
