function [255:0] probe_mem_val;
input [3:0] row;
reg [255:0] data;
begin

// probing RAMDP_16X256_GL_M1_E2
 if (row >=  0 &&  row < 16) data[255:0] = r_nv_ram_rws_16x256.ram_Inst_16X256.mem_read(row - 0);
    probe_mem_val = data;

end
endfunction
